import re
import pandas as pd
from collections import defaultdict

# Load the books data from the file
books_file = var_functions.query_db:8
if isinstance(books_file, str) and books_file.endswith('.json'):
    with open(books_file, 'r') as f:
        books_data = json.load(f)
else:
    books_data = books_file

# Extract publication year from details
def extract_year(details_str):
    if not details_str:
        return None
    # Look for 4-digit years in the string
    years = re.findall(r'\b(19\d{2}|20\d{2})\b', str(details_str))
    if years:
        return int(years[0])
    return None

# Process books data
books_df_data = []
for book in books_data:
    year = extract_year(book.get('details', ''))
    if year:
        decade = f"{year//10*10}s"
        books_df_data.append({
            'book_id': book.get('book_id'),
            'year': year,
            'decade': decade
        })

books_df = pd.DataFrame(books_df_data)
print('__RESULT__:')
print(json.dumps({
    'total_books_with_year': len(books_df),
    'sample_books': books_df.head(10).to_dict('records')
}))

