import json
import re
from collections import defaultdict

# Load books data
books_file_key = 'var_functions.query_db:22'
books_file = locals()[books_file_key]
if isinstance(books_file, str) and books_file.endswith('.json'):
    with open(books_file, 'r') as f:
        books_data = json.load(f)
else:
    books_data = books_file

# Load reviews data
reviews_file_key = 'var_functions.query_db:23'
reviews_file = locals()[reviews_file_key]
if isinstance(reviews_file, str) and reviews_file.endswith('.json'):
    with open(reviews_file, 'r') as f:
        reviews_data = json.load(f)
else:
    reviews_data = reviews_file

# Extract publication year from details
def extract_year(details_str):
    if not details_str:
        return None
    # Look for 4-digit years between 1900-2023
    years = re.findall(r'\b(19\d{2}|20[0-2]\d)\b', str(details_str))
    if years:
        return int(years[0])
    return None

# Process books: extract year and map book_id to decade
books_by_id = {}
for book in books_data:
    book_id = book.get('book_id')
    details = book.get('details', '')
    year = extract_year(details)
    if year:
        decade = (year // 10) * 10
        books_by_id[book_id] = decade

# Process reviews: map book_id to list of ratings
ratings_by_book = defaultdict(list)
for review in reviews_data:
    purchase_id = review.get('purchase_id')
    rating = float(review.get('rating', 0))
    if purchase_id and purchase_id.startswith('purchaseid_'):
        book_id = purchase_id.replace('purchaseid_', 'bookid_', 1)
        ratings_by_book[book_id].append(rating)

# Calculate average rating per book
book_avg_rating = {}
for book_id, ratings in ratings_by_book.items():
    if ratings:  # Only include books that have ratings
        book_avg_rating[book_id] = sum(ratings) / len(ratings)

# Group books by decade and calculate stats
decade_stats = defaultdict(lambda: {'books': set(), 'total_rating': 0, 'book_count': 0})

for book_id, avg_rating in book_avg_rating.items():
    if book_id in books_by_id:
        decade = books_by_id[book_id]
        decade_stats[decade]['books'].add(book_id)
        decade_stats[decade]['total_rating'] += avg_rating
        decade_stats[decade]['book_count'] += 1

# Filter decades with at least 10 distinct books and calculate average
decade_averages = {}
for decade, stats in decade_stats.items():
    if len(stats['books']) >= 10:
        decade_averages[decade] = stats['total_rating'] / stats['book_count']

# Find decade with highest average rating
if decade_averages:
    best_decade = max(decade_averages.items(), key=lambda x: x[1])
    result = {
        'decade': f"{best_decade[0]}s",
        'average_rating': round(best_decade[1], 3),
        'book_count': len(decade_stats[best_decade[0]]['books'])
    }
else:
    result = {'error': 'No decades found with at least 10 books'}

print('__RESULT__:')
print(json.dumps(result, indent=2))

