        best_decade = max(decade_averages.items(), key=lambda x: x[1][0])
        result = {
            'decade': best_decade[0],
            'avg_rating': round(best_decade[1][0], 3),
            'rated_books': best_decade[1][1]
        }
    else:
        result = {'error': 'No decades with 10+ rated books'}
else:
    result = {'error': f'Missing data: books={bool(books_data)}, reviews={bool(reviews_data)}'}

print('__RESULT__:')
print(json.dumps(result))
